module RefModule(CLK, RST, Q);
input CLK, RST;
output reg [3:0] Q;

reg [3:0] obf_bin_counter;

always @(posedge CLK or posedge RST) begin
    if (RST)
        obf_bin_counter <= 4'b0000;
    else
        obf_bin_counter <= obf_bin_counter + 1'b1;
end

always @(obf_bin_counter) begin
    Q = obf_bin_counter ^ (obf_bin_counter >> 1);
end

endmodule
